# Validators module: Input validation and range checking

from geometry import Shape, Rectangle

class ValidationResult:
    is_valid: bool
    message: str

    def __init__(self, valid: bool, msg: str):
        self.is_valid = valid
        self.message = msg

def validate_positive(value: float) -> ValidationResult:
    if value > 0.0:
        return ValidationResult(True, "Value is positive")
    return ValidationResult(False, "Value must be positive")

def validate_shape_dimensions(shape: Shape) -> bool:
    area: float = shape.area()
    perimeter: float = shape.perimeter()
    return area > 0.0 and perimeter > 0.0

class RangeValidator:
    min_value: float
    max_value: float

    def __init__(self, min_val: float, max_val: float):
        self.min_value = min_val
        self.max_value = max_val

    def is_in_range(self, value: float) -> bool:
        return value >= self.min_value and value <= self.max_value
